export const exploreFailureReason = {
	subscribe(run) {
		return grid.subscribe(($grid) => run($grid.exploreFailureReason));
	},
};

export function getDisplayedCandidates(state, x, y, notesEnabled) {
	const value = state.grid[y][x];
	if (value !== 0) {
		return null;
	}

	const manual = state.candidateMarks[toCellKey(y, x)];
	if (manual && manual.length > 0) {
		return manual;
	}

	if (!notesEnabled) {
		return null;
	}

	const candidates = [];
	for (let candidate = 1; candidate <= BOX_SIZE * BOX_SIZE; candidate += 1) {
		if (!state.invalidCells.includes(toCellKey(y, x))) {
			candidates.push(candidate);
		}
	}

	return candidates;
}
